"""
generate_comprehensive.py
Generates strategic_comprehensive.json with full SWOT, goals, KPIs etc.
for all 12 governorates, based on data.json and strategic_plans.json.
"""

import json

data = json.load(open('src/data.json', encoding='utf-8'))
plans = json.load(open('src/strategic_plans.json', encoding='utf-8'))

try:
    existing = json.load(open('src/strategic_comprehensive.json', encoding='utf-8'))
except:
    existing = {}

GOVERNORATES = [
    "العاصمة", "البلقاء", "الزرقاء", "مأدبا",
    "إربد", "المفرق", "جرش", "عجلون",
    "الكرك", "الطفيلة", "معان", "العقبة",
]

sector_labels = {
    'التعليم': 'التعليم', 'الصحة': 'الصحة', 'الزراعة': 'الزراعة',
    'السياحة': 'السياحة', 'البنية التحتية': 'البنية التحتية',
    'المياه والصرف الصحي': 'المياه والصرف الصحي',
    'البطالة': 'البطالة', 'الثقافة والمجتمع': 'الثقافة والمجتمع'
}

def get_sectors_for_gov(name):
    for g in data['governorates']:
        if g['name'] == name:
            return g['sectors']
    return {}

def get_raw_for_gov(name):
    for g in data['governorates']:
        if g['name'] == name:
            return g.get('raw_data', {})
    return {}

def get_competitive_advantages(name):
    for g in data['governorates']:
        if g['name'] == name:
            return g.get('competitive_advantages', [])
    return []

def strength_sectors(sectors):
    return [s for s, d in sectors.items() if d['status'] == 'متقدم']

def weakness_sectors(sectors):
    return [s for s, d in sectors.items() if d['status'] == 'متأخر']

def avg_sectors(sectors):
    return [s for s, d in sectors.items() if d['status'] == 'متوسط']

# ---- Generate comprehensive for each gov ----
result = {}

for name in GOVERNORATES:
    if name in existing:
        result[name] = existing[name]
        continue

    plan = plans.get(name, {})
    sectors = get_sectors_for_gov(name)
    strengths = strength_sectors(sectors)
    weaknesses = weakness_sectors(sectors)
    avg_secs = avg_sectors(sectors)

